当 CPU 执行到 trap 函数后，会进入 trap_dispatch 函数进一步的分发，根据 tf->tf_trapno 字段来判断 T_SYSCALL 类型。这个函数的参数 tf 是一个指向 Trapframe 结构的指针，这个结构包含了发生中断或异常时 CPU 的状态。 void
trap(struct Trapframe *tf)
{ // ... trap_dispatch(tf); // ...
} static void
trap_dispatch(struct Trapframe *tf)
{ switch (tf->tf_trapno) { case T_PGFLT: page_fault_handler(tf); return; case T_BRKPT: monitor(tf); return; case T_SYSCALL: tf->tf_regs.reg_eax = syscall(tf->tf_regs.reg_eax, tf->tf_regs.reg_edx, tf->tf_regs.reg_ecx, tf->tf_regs.reg_ebx, tf->tf_regs.reg_edi, tf->tf_regs.reg_esi); return; default: break; } // ...
} 根据参数做进一步的区分后会调用 sys_getenvid() 。 int32_t
syscall(uint32_t syscallno, uint32_t a1, uint32_t a2, uint32_t a3, uint32_t a4, uint32_t a5)
{ int32_t ret; switch (syscallno) { // ... case SYS_getenvid: ret = sys_getenvid(); break; // ... default: return -E_INVAL; } return ret;
} static envid_t
sys_getenvid(void)
{ return curenv->env_id;
}

