下面这段代码用于释放一个自旋锁。 // Release the lock.
void
spin_unlock(struct spinlock *lk)
{
#ifdef DEBUG_SPINLOCK if (!holding(lk)) { int i; uint32_t pcs[10]; // Nab the acquiring EIP chain before it gets released memmove(pcs, lk->pcs, sizeof pcs); cprintf("CPU %d cannot release %s: held by CPU %d\nAcquired at:", cpunum(), lk->name, lk->cpu->cpu_id); for (i = 0; i < 10 && pcs[i]; i++) { struct Eipdebuginfo info; if (debuginfo_eip(pcs[i], &info) >= 0) cprintf(" %08x %s:%d: %.*s+%x\n", pcs[i], info.eip_file, info.eip_line, info.eip_fn_namelen, info.eip_fn_name, pcs[i] - info.eip_fn_addr); else cprintf(" %08x\n", pcs[i]); } panic("spin_unlock"); } lk->pcs[0] = 0; lk->cpu = 0;
#endif // The xchg instruction is atomic (i.e. uses the "lock" prefix) with // respect to any other instruction which references the same memory. // x86 CPUs will not reorder loads/stores across locked instructions // (vol 3, 8.2.2). Because xchg() is implemented using asm volatile, // gcc will not reorder C statements across the xchg. xchg(&lk->locked, 0);
