下面的代码挺容易理解的，直接模拟即可。 class Solution {
public: vector<vector<int>> generateMatrix(int n) { // 创建一个n*n的矩阵，初始值为0 vector<vector<int>> matrix(n, vector<int>(n , 0)); // 定义四个方向的边界：左、右、上、下 int left = 0 , right = n - 1; int top = 0, down = n - 1; // 初始数字从1开始 int num = 1; // 当左边界不超过右边界，且上边界不超过下边界时，循环继续 while (left <= right && top <= down) { // 从左到右填充上边界的行 for (int i = left; i <= right; i++) { matrix[top][i] = num++; // 填充并将num递增 } top++; // 上边界下移 // 从上到下填充右边界的列 for (int i = top; i <= down; i++) { matrix[i][right] = num++; // 填充并将num递增 } right--; // 右边界左移 // 从右到左填充下边界的行 for (int i = right; i >= left; i--) { matrix[down][i] = num++; // 填充并将num递增 } down--; // 下边界上移 // 从下到上填充左边界的列 for (int i = down; i >= top; i--) { matrix[i][left] = num++; // 填充并将num递增 } left++; // 左边界右移 } // 返回填充完成的矩阵 return matrix; }
}; 此代码通过不断缩小矩阵的边界（左、右、上、下）来实现螺旋填充。每完成矩阵的一圈（即一层）的填充后，相应地调整边界条件，直到所有数字都被填充到矩阵中。这种方式有效地利用了螺旋路径的模式，确保了填充顺序的正确性和高效性。

