下面是完整代码： class Skiplist {
public: static const int level = 8; // 定义跳表的最大层数为 8，这是一个经验值，太大会造成空间浪费 // 跳表节点的结构定义 struct Node { int val; // 节点存储的值 vector<Node*> next; // 存储到下一个节点的指针数组，next[i] 表示当前节点在第 i 层的下一个节点 Node(int _val) : val(_val) { // 构造函数，初始化节点值和 next 数组 next.resize(level, NULL); // 将 next 数组的大小初始化为 level，并全部指向 NULL } }*head; // 跳表的头节点，初始化时指向一个虚拟节点 // 构造函数 Skiplist() { head = new Node(-1); // 初始化头节点，使用一个不存在的节点值（这里用 -1） } // 析构函数 ~Skiplist() { Node *current = head; while (current) { Node *temp = current; current = current->next[0]; // 遍历链表，释放每个节点的内存 delete temp; } } // 辅助函数：找到小于目标值 target 的每一层的最大节点 void find(int target, vector<Node*>& p) { Node* node = head; for (int i = level - 1; i >= 0; i--) { while (node->next[i] && node->next[i]->val < target) { node = node->next[i]; // 在第 i 层向前移动，直到找到小于 target 的最大节点 } p[i] = node; // 存储每一层找到的节点 } } // 查找函数：判断跳表中是否存在值为 target 的节点 bool search(int target) { vector<Node*> pre(level); find(target, pre); // 找到每一层小于 target 的最大节点 auto p = pre[0]->next[0]; // 在最底层判断是否存在 target return p && p->val == target; // 如果存在且值相等，返回 true } // 插入函数：向跳表中插入一个值为 num 的新节点 void add(int num) { vector<Node*> pre(level); find(num, pre); // 找到每一层小于 num 的最大节点 auto p = new Node(num); // 创建新节点 for (int i = 0; i < level; i++ ) { p->next[i] = pre[i]->next[i]; // 新节点的 next 指向前驱节点的 next pre[i]->next[i] = p; // 前驱节点的 next 指向新节点 if (rand() % 2) break; // 有 50% 的概率停止向上层插入 } } // 删除函数：从跳表中删除值为 num 的节点 bool erase(int num) { vector<Node*> pre(level); find(num, pre); // 找到每一层小于 num 的最大节点 auto p = pre[0]->next[0]; // 检查最底层是否存在要删除的节点 if (!p || p->val != num) return false; // 如果不存在，返回 false // 存在则从每一层中删除 for (int i = 0; i < level && pre[i]->next[i] == p; i++) { pre[i]->next[i] = p->next[i]; // 将前驱节点的 next 指向要删除节点的下一个节点 } delete p; // 释放被删除节点的内存 return true; }
}; /** * Skiplist 对象的实例化和使用： * Skiplist* obj = new Skiplist(); * bool param_1 = obj->search(target); * obj->add(num); * bool param_3 = obj->erase(num); */

