这段代码实现了一个称为“Trie”（也被称为前缀树或字典树）的数据结构。以下是对代码的逐行中文注释： // Trie节点的定义。
class TrieNode {
public: bool isEndOfWord; // 标记这个节点是否是某个单词的结尾 unordered_map<char, TrieNode*> children; // 存储当前节点的子节点 // 构造函数，初始化时该节点不是任何单词的结尾 TrieNode() : isEndOfWord(false) {}
}; // Trie树的定义。
class Trie {
private: TrieNode* root; // Trie树的根节点 public: // 构造函数，初始化Trie树时创建根节点 Trie() { root = new TrieNode(); } // 向Trie树中插入一个单词 void insert(string word) { TrieNode* current = root; // 从根节点开始 for (char ch : word) { // 遍历单词的每一个字符 // 如果当前字符不在子节点中，则添加它 if (current->children.find(ch) == current->children.end()) { current->children[ch] = new TrieNode(); } // 移动到下一个节点 current = current->children[ch]; } // 标记单词的最后一个字符为单词的结尾 current->isEndOfWord = true; } // 搜索Trie树中是否存在某个单词 bool search(string word) { TrieNode* current = root; // 从根节点开始 for (char ch : word) { // 遍历单词的每一个字符 // 如果当前字符不在子节点中，返回false if (current->children.find(ch) == current->children.end()) { return false; } // 移动到下一个节点 current = current->children[ch]; } // 如果找到最后一个字符，并且这个字符是某个单词的结尾，则返回true return current != nullptr && current->isEndOfWord; } // 检查Trie树中是否有以某个前缀开始的单词 bool startsWith(string prefix) { TrieNode* current = root; // 从根节点开始 for (char ch : prefix) { // 遍历前缀的每一个字符 // 如果当前字符不在子节点中，返回false if (current->children.find(ch) == current->children.end()) { return false; } // 移动到下一个节点 current = current->children[ch]; } // 如果前缀存在，则返回true return true; } // 析构函数，释放Trie树所占用的所有内存 ~Trie() { clearMemory(root); } private: // 递归清理内存的辅助函数 void clearMemory(TrieNode* node) { // 递归清理所有子节点 for (auto pair : node->children) { clearMemory(pair.second); } // 删除当前节点 delete node; }
}; 这个 Trie 树的实现提供了插入单词、搜索单词和搜索以某个前缀开始的单词的功能，同时在析构时清理所有占用的内存。Trie 树是一种高效的字符串检索数据结构，常用于实现字典、自动补全等功能。

